import strawberry
from strawberry.fastapi import GraphQLRouter
from fastapi import FastAPI
from sqlalchemy import create_engine, Column, Integer, String, Float, ForeignKey, Table, Text
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker, relationship, Session
from typing import List, Optional
from contextlib import asynccontextmanager

DATABASE_URL = "sqlite:///./products.db"
engine = create_engine(DATABASE_URL, connect_args={"check_same_thread": False})
SessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)
Base = declarative_base()

product_categories = Table(
    'product_categories',
    Base.metadata,
    Column('product_id', Integer, ForeignKey('products.id')),
    Column('category_id', Integer, ForeignKey('categories.id'))
)

class ProductModel(Base):
    __tablename__ = "products"
    
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)
    description = Column(Text)
    price = Column(Float)
    seller_id = Column(Integer, ForeignKey("sellers.id"))
    
    seller = relationship("SellerModel", back_populates="products")
    reviews = relationship("ReviewModel", back_populates="product")
    images = relationship("ImageModel", back_populates="product")
    categories = relationship("CategoryModel", secondary=product_categories, back_populates="products")

class SellerModel(Base):
    __tablename__ = "sellers"
    
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)
    email = Column(String)
    rating = Column(Float)
    
    products = relationship("ProductModel", back_populates="seller")

class ReviewModel(Base):
    __tablename__ = "reviews"
    
    id = Column(Integer, primary_key=True, index=True)
    product_id = Column(Integer, ForeignKey("products.id"))
    author = Column(String)
    rating = Column(Integer)
    comment = Column(Text)
    
    product = relationship("ProductModel", back_populates="reviews")

class CategoryModel(Base):
    __tablename__ = "categories"
    
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)
    description = Column(Text)
    parent_id = Column(Integer, ForeignKey("categories.id"), nullable=True)
    
    parent = relationship("CategoryModel", remote_side=[id], back_populates="subcategories")
    subcategories = relationship("CategoryModel", back_populates="parent")
    products = relationship("ProductModel", secondary=product_categories, back_populates="categories")

class ImageModel(Base):
    __tablename__ = "images"
    
    id = Column(Integer, primary_key=True, index=True)
    product_id = Column(Integer, ForeignKey("products.id"))
    url = Column(String)
    alt_text = Column(String)
    
    product = relationship("ProductModel", back_populates="images")

Base.metadata.create_all(bind=engine)

def get_db():
    db = SessionLocal()
    try:
        return db
    finally:
        db.close()

def init_data():
    db = SessionLocal()
    
    if db.query(ProductModel).count() > 0:
        db.close()
