@strawberry.type
class Product:
    id: int
    name: str
    description: str
    price: float
    
    @strawberry.field
    def seller(self, info) -> Seller:
        db = info.context["db"]
        product = db.query(ProductModel).filter(ProductModel.id == self.id).first()
        return Seller(
            id=product.seller.id,
            name=product.seller.name,
            email=product.seller.email,
            rating=product.seller.rating
        )
    
    @strawberry.field
    def reviews(self, info) -> List[Review]:
        db = info.context["db"]
        product = db.query(ProductModel).filter(ProductModel.id == self.id).first()
        return [Review(
            id=r.id,
            author=r.author,
            rating=r.rating,
            comment=r.comment
        ) for r in product.reviews]
    
    @strawberry.field
    def images(self, info) -> List[Image]:
        db = info.context["db"]
        product = db.query(ProductModel).filter(ProductModel.id == self.id).first()
        return [Image(
            id=img.id,
            url=img.url,
            alt_text=img.alt_text
        ) for img in product.images]
    
    @strawberry.field
    def categories(self, info) -> List[Category]:
        db = info.context["db"]
        product = db.query(ProductModel).filter(ProductModel.id == self.id).first()
        return [Category(
            id=c.id,
            name=c.name,
            description=c.description
        ) for c in product.categories]

@strawberry.type
class Query:
    @strawberry.field
    def products(self, info) -> List[Product]:
        db = info.context["db"]
        products = db.query(ProductModel).all()
        return [Product(
            id=p.id,
            name=p.name,
            description=p.description,
            price=p.price
        ) for p in products]
    
    @strawberry.field
    def product(self, info, id: int) -> Optional[Product]:
        db = info.context["db"]
        product = db.query(ProductModel).filter(ProductModel.id == id).first()
        if product:
            return Product(
                id=product.id,
                name=product.name,
                description=product.description,
                price=product.price
            )
        return None
    
    @strawberry.field
    def sellers(self, info) -> List[Seller]:
        db = info.context["db"]
        sellers = db.query(SellerModel).all()
        return [Seller(
            id=s.id,
            name=s.name,
            email=s.email,
            rating=s.rating
        ) for s in sellers]
    
    @strawberry.field
    def categories(self, info) -> List[Category]:
        db = info.context["db"]
        categories = db.query(CategoryModel).all()
        return [Category(
            id=c.id,
            name=c.name,
            description=c.description
        ) for c in categories]

def get_context():
    return {"db": get_db()}

schema = strawberry.Schema(query=Query)

app = FastAPI()

graphql_app = GraphQLRouter(schema, context_getter=get_context)

app.include_router(graphql_app, prefix="/graphql")

init_data()

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)